python3 -c '
import re, sys

# Build set of all defined anchors and attribute references in BUS0 + included subdocs
defined = set()
files = ["Tools/buk/vov_veiled/BUS0-BashUtilitiesSpec.adoc"]
for f in [
    "BUSD-DispatchRuntime.adoc",
    "BUSTLL-NodeRegimeList.adoc","BUSTLR-NodeRegimeRender.adoc","BUSTLV-NodeRegimeValidate.adoc",
    "BUSTPL-PrivilegeRegimeList.adoc","BUSTPR-PrivilegeRegimeRender.adoc","BUSTPV-PrivilegeRegimeValidate.adoc",
    "BUSJGB-GarrisonBash.adoc","BUSJGC-GarrisonCygwin.adoc","BUSJGW-GarrisonWsl.adoc",
    "BUSJWK-Knock.adoc","BUSJWC-CommandFile.adoc","BUSJWS-InteractiveSession.adoc",
    "BUSJH0-HandbookJurisdictionTop.adoc",
]:
    files.append(f"Tools/buk/vov_veiled/{f}")

# Collect defined anchors [[name]] and attribute :name:
attrs = set()
anchors = set()
for path in files:
    try:
        text = open(path).read()
    except FileNotFoundError:
        print(f"MISSING include target: {path}")
        continue
    for m in re.finditer(r"\[\[([a-zA-Z0-9_]+)\]\]", text):
        anchors.add(m.group(1))
    for m in re.finditer(r"^:([a-zA-Z0-9_]+):\s", text, re.MULTILINE):
        attrs.add(m.group(1))

# Now scan {token} interpolations and <<anchor,...>> refs
issues = []
for path in files:
    try:
        text = open(path).read()
    except FileNotFoundError:
        continue
    for ln, line in enumerate(text.splitlines(), 1):
        if line.lstrip().startswith("//"):
            continue
        for m in re.finditer(r"\{([a-zA-Z0-9_]+)\}", line):
            tok = m.group(1)
            # Skip a few known non-quoin references like BURD_OUTPUT_DIR uppercase env
            if tok != tok.lower():
                continue
